gV0(){return"\u0623\u064a \u0646\u0648\u0639 \u0645\u0646 \u0642\u0634\u0631\u0629 \u0627\u0644\u0628\u064a\u062a\u0632\u0627 \u062e\u0627\u0644\u064d \u0645\u0646 \u0627\u0644\u063a\u0644\u0648\u062a\u064a\u0646\u061f"},
