gNt(){return"\u0627\u0644\u062d\u0633\u0627\u0628"},
gNI(){return"\u0627\u0644\u0645\u0638\u0647\u0631"},
gNp(){return"\u062d\u0648\u0644 \u0627\u0644\u062a\u0637\u0628\u064a\u0642"},
gNG(){return"\u062a\u0645 \u062a\u0635\u0645\u064a\u0645 \u0647\u0630\u0627 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0644\u0645\u0633\u0627\u0639\u062f\u0629 \u0627\u0644\u0623\u0634\u062e\u0627\u0635 \u0627\u0644\u0645\u0635\u0627\u0628\u064a\u0646 \u0628\u0645\u0631\u0636 \u0627\u0644\u0627\u0636\u0637\u0631\u0627\u0628\u0627\u062a \u0627\u0644\u0647\u0636\u0645\u064a\u0629 \u0623\u0648 \u0639\u062f\u0645 \u062a\u062d\u0645\u0644 \u0627\u0644\u063a\u0644\u0648\u062a\u064a\u0646 \u0645\u0646 \u062e\u0644\u0627\u0644 \u062a\u0648\u0641\u064a\u0631 \u0645\u0646\u0635\u0629 \u062a\u062c\u0627\u0631\u0629 \u0625\u0644\u0643\u062a\u0631\u0648\u0646\u064a\u0629 \u0622\u0645\u0646\u0629\u060c \u0648\u0648\u0635\u0641\u0627\u062a \u0645\u0646\u0627\u0633\u0628\u0629\u060c \u0648\u0623\u0644\u0639\u0627\u0628 \u062a\u0639\u0644\u064a\u0645\u064a\u0629 \u0648\u0645\u0648\u0627\u0631\u062f \u0644\u0644\u062d\u0641\u0627\u0638 \u0639\u0644\u0649 \u0646\u0645\u0637 \u062d\u064a\u0627\u0629 \u062e\u0627\u0644\u064d \u0645\u0646 \u0627\u0644\u063a\u0644\u0648\u062a\u064a\u0646 \u0628\u0623\u0645\u0627\u0646."},
